async function main() {
  let success = 0;
  let fail = 0;

  for (const u of updates) {
    try {
      const desc = u.description.trim();
      const meta = u.metaDescription.trim();
      const wordCount = desc.split(/\s+/).length;
      const metaLen = meta.length;

      if (wordCount < 250) {
        console.error(`FAIL [${u.slug}] description word count: ${wordCount} (need 250+)`);
        fail++;
        continue;
      }
      if (metaLen < 130 || metaLen > 155) {
        console.error(`FAIL [${u.slug}] meta description length: ${metaLen} (need 130-155)`);
        fail++;
        continue;
      }

      await prisma.product.update({
        where: { slug: u.slug },
        data: { description: desc, metaDescription: meta },
      });

      console.log(`OK [${u.slug}] words=${wordCount} metaLen=${metaLen}`);
      success++;
    } catch (err) {
      console.error(`ERROR [${u.slug}] ${err.message}`);
      fail++;
    }
  }

  console.log(`\nDone: ${success} updated, ${fail} failed, ${success + fail} total`);
}

main()
  .catch((e) => { console.error(e); process.exit(1); })
  .finally(() => prisma.$disconnect());
